```csharp
public class BaseRepository<T> : IBaseRepository<T> where T : class
{
    protected readonly DbContext _context;
    protected readonly DbSet<T> _dbSet;

    public BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<T>();
    }

    public virtual async Task<T> GetByIdAsync(int id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<T> GetByDynamicAsync(object filter)
    {
        var query = _dbSet.AsQueryable();

        if (filter is Dictionary<string, object> filterDict)
        {
            foreach (var property in filterDict)
            {
                var parameter = Expression.Parameter(typeof(T));
                var member = Expression.PropertyOrField(parameter, property.Key);
                var constant = Expression.Constant(property.Value);
                var body = Expression.Equal(member, constant);
                var lambda = Expression.Lambda<Func<T, bool>>(body, parameter);
                query = query.Where(lambda);
